/**
 * KHO CÂU "GÓC NGƯỢC" CHO PA — v3 (nhom_nhan added 10/06/2026)
 * Datamined: 09/06/2026 · 487 câu độc nhất (dọn 13 trùng chéo-nhóm 10/06)
 * Tỷ lệ: ~50% VN tục ngữ/bình dân · ~20% EN (kèm dịch VN) · ~15% quote · ~15% trend
 * Tiếng Anh: kèm bản dịch trong ()
 */

export type NguonLoai = "tucngu"|"thanhngu_en"|"quote"|"trend"|"binhdan"|"tho"
export type Vung = "🟢"|"🟡"|"🔴-cam"
export type SacThai = "đùa"|"sắc"|"nhẹ"|"sâu-lắng"
export type Tuoi = "moi-tuoi"|"tre"|"lon-tuoi"
export type NgonNgu = "VN"|"EN"
export type DoBen = "vinh-cuu"|"nhieu-nam"|"trend-de-het-han"
export type NhomNhan = "all"|"ABC"|"CD"
// all = mọi nhóm · ABC = loại nhóm D (Turbulent-Feeling, nhạy nhất) · CD = chỉ nhóm nhạy (câu 🟡)
export type DoTinCay = "co_nguon"|"pho_bien_chua_xac_minh"

export interface GocNguocCau {
  id: string
  cau: string
  nghia: string
  nguon_loai: NguonLoai
  tac_gia: string
  do_tin_cay?: DoTinCay
  ngu_canh: string[]
  vung: Vung
  sac_thai: SacThai
  tuoi: Tuoi
  ngon_ngu: NgonNgu
  do_ben: DoBen
  nhom_nhan: NhomNhan  // A=Assertive-T · B=Assertive-F · C=Turbulent-T · D=Turbulent-F
}

const p = (id:string,cau:string,nghia:string,nguon_loai:NguonLoai,tac_gia:string,ngu_canh:string[],vung:Vung,sac_thai:SacThai,tuoi:Tuoi,ngon_ngu:NgonNgu,do_ben:DoBen,do_tin_cay_or_nhom:DoTinCay|NhomNhan|undefined,nhom_nhan?:NhomNhan):GocNguocCau => {
  const do_tin_cay = (do_tin_cay_or_nhom === "co_nguon"||do_tin_cay_or_nhom === "pho_bien_chua_xac_minh") ? do_tin_cay_or_nhom : undefined
  const nhom = nhom_nhan ?? (do_tin_cay_or_nhom !== "co_nguon" && do_tin_cay_or_nhom !== "pho_bien_chua_xac_minh" ? do_tin_cay_or_nhom as NhomNhan : "all") ?? "all"
  return {id,cau,nghia,nguon_loai,tac_gia,do_tin_cay,ngu_canh,vung,sac_thai,tuoi,ngon_ngu,do_ben,nhom_nhan:nhom}
}

